def {{nama_decorator}}(func=None, output='{{output}}', label=None):
    """Timer decorator. Measures wall-clock execution time.
    output: 'print' (to stderr), 'return' (add elapsed to return tuple), 'log' (via logging).
    Usage: @timer or @timer(output='return')
    """
    import sys
    import logging

    def _decorator(fn):
        @functools.wraps(fn)
        def wrapper(*args, **kwargs):
            start = time.perf_counter()
            result = fn(*args, **kwargs)
            elapsed = time.perf_counter() - start
            name = label or fn.__name__
            if output == 'print':
                sys.stderr.write('[TIMER] %s: %.4f s\n' % (name, elapsed))
            elif output == 'log':
                logging.getLogger(name).info('executed in %.4f s', elapsed)
            elif output == 'return':
                return result, elapsed
            return result
        return wrapper

    if func is not None:
        return _decorator(func)
    return _decorator

def {{nama_decorator}}(func=None, maxsize={{maxsize}}, ttl=None):
    """Memoization decorator with optional maxsize and TTL.
    Cache key based on positional + keyword args.
    Usage: @memoize or @memoize(maxsize=256, ttl=60)
    """
    def _decorator(fn):
        cache = {}
        timestamps = {}
        lock = threading.Lock()
        hits = [0]
        misses = [0]

        def _make_key(args, kwargs):
            return (args, tuple(sorted(kwargs.items())))

        @functools.wraps(fn)
        def wrapper(*args, **kwargs):
            key = _make_key(args, kwargs)
            with lock:
                if key in cache:
                    if ttl is None or (time.time() - timestamps[key]) < ttl:
                        hits[0] += 1
                        return cache[key]
                    else:
                        del cache[key]
                        del timestamps[key]
                misses[0] += 1
            result = fn(*args, **kwargs)
            with lock:
                cache[key] = result
                timestamps[key] = time.time()
                if maxsize and len(cache) > maxsize:
                    oldest_key = min(timestamps, key=timestamps.get)
                    del cache[oldest_key]
                    del timestamps[oldest_key]
            return result

        def cache_clear():
            with lock:
                cache.clear()
                timestamps.clear()
                hits[0] = 0
                misses[0] = 0

        def cache_info():
            return {'hits': hits[0], 'misses': misses[0], 'size': len(cache)}

        wrapper.cache_clear = cache_clear
        wrapper.cache_info = cache_info
        return wrapper

    if func is not None:
        return _decorator(func)
    return _decorator
